import{_ as o,N as t,o as n,a as i,e as l,i as r}from"./chunks/framework.DW6Cm6Mn.js";const u=JSON.parse('{"title":"O jazyce Vala","description":"Vala je objektově orientovaný programovací jazyk s vlastním kompilátorem, který generuje kód v jazyce C a používá typový systém GObject.","frontmatter":{"title":"O jazyce Vala","description":"Vala je objektově orientovaný programovací jazyk s vlastním kompilátorem, který generuje kód v jazyce C a používá typový systém GObject."},"headers":[],"relativePath":"cs/about/index.md","filePath":"cs/about/index.md"}'),s={name:"cs/about/index.md"};function k(p,a,v,c,m,y){const e=t("PredefinedCtaStack");return n(),i("div",null,[a[0]||(a[0]=l('<h1 id="o-jazyce-vala" tabindex="-1">O jazyce Vala <a class="header-anchor" href="#o-jazyce-vala" aria-label="Permalink to &quot;O jazyce Vala&quot;">​</a></h1><h2 id="co-je-vala" tabindex="-1">Co je Vala? <a class="header-anchor" href="#co-je-vala" aria-label="Permalink to &quot;Co je Vala?&quot;">​</a></h2><p>Vala je objektově orientovaný programovací jazyk s vlastním kompilátorem, který generuje kód v jazyce C a používá typový systém GObject.</p><p>Vala podporuje moderní jazykové funkce, jako jsou:</p><ul><li>Rozhraní</li><li>Vlastnosti</li><li>Signály</li><li>Konstrukce Foreach</li><li>Výrazy lambda</li><li>Odvozování typu pro místní proměnné</li><li>Generické typy</li><li>Ne-nullové typy</li><li>Asistovanou správu paměti</li><li>Zacházení s výjimkami</li><li>Typové moduly (pluginy)</li></ul><h2 id="jakym-jazykem-je-vala" tabindex="-1">Jakým jazykem je Vala? <a class="header-anchor" href="#jakym-jazykem-je-vala" aria-label="Permalink to &quot;Jakým jazykem je Vala?&quot;">​</a></h2><h3 id="produktivni" tabindex="-1">Produktivní <a class="header-anchor" href="#produktivni" aria-label="Permalink to &quot;Produktivní&quot;">​</a></h3><p>S Valou můžete začít pracovat rychle díky praktickým funkcím, jako jsou lambda výrazy, zpracování výjimek, rozhraní a generika.</p><h3 id="vykonny" tabindex="-1">Výkonný <a class="header-anchor" href="#vykonny" aria-label="Permalink to &quot;Výkonný&quot;">​</a></h3><p>Kód Vala se zkompiluje na plně nativní binární soubory.</p><h3 id="staticky-typovany" tabindex="-1">Staticky typovaný <a class="header-anchor" href="#staticky-typovany" aria-label="Permalink to &quot;Staticky typovaný&quot;">​</a></h3><p>Vala vám pomůže psát typově bezpečný kód bez zbytečných slov, a to díky odvozování typů.</p><h3 id="integrativni" tabindex="-1">Integrativní <a class="header-anchor" href="#integrativni" aria-label="Permalink to &quot;Integrativní&quot;">​</a></h3><p>Vala je navržena tak, aby umožňovala přístup k existujícím knihovnám jazyka C, zejména ke knihovnám založeným na GObject, bez nutnosti runtime vazeb. Vše, co je potřeba k použití knihovny s Valou, je soubor API obsahující deklarace tříd a metod v syntaxi Vala. Vala v současné době obsahuje vazby pro GLib a GTK+ a mnoho dalších z platformy GNOME.</p><p>Vala lze použít k vytváření knihoven také v jazyce C.</p><h3 id="znamy" tabindex="-1">Známý <a class="header-anchor" href="#znamy" aria-label="Permalink to &quot;Známý&quot;">​</a></h3><p>Syntaxe jazyka Vala je inspirována jazyky C# a Java, takže pokud jste některý z nich používali, snadno se přizpůsobíte psaní kódu jazyka Vala.</p>',17)),r(e)])}const j=o(s,[["render",k]]);export{u as __pageData,j as default};
